+    stop: async () => {
+      for (const svc of services) {
+        try {
+          await svc.destroy();
+        } catch {
+          /* ignore */
+        }
+      }
+      try {
+        await responder.shutdown();
+      } catch {
+        /* ignore */
+      }
+    },
+  };
