+type AnyBridgeFrame =
+  | BridgeHelloFrame
+  | BridgePairRequestFrame
+  | BridgeEventFrame
+  | BridgePingFrame
+  | BridgePongFrame
+  | BridgeInvokeResponseFrame
+  | BridgeHelloOkFrame
+  | BridgePairOkFrame
+  | BridgeErrorFrame
+  | { type: string; [k: string]: unknown };
